import json
import re
import os
from time import sleep
from openai import AzureOpenAI
from math import ceil

azure_openai_api_key = os.getenv("AZURE_OPENAI_API_KEY", "")
azure_openai_api_version = os.getenv("AZURE_OPENAI_API_VERSION", "2025-04-01-preview")
azure_openai_endpoint = os.getenv("AZURE_OPENAI_ENDPOINT", "")
model_name = os.getenv("AZURE_OPENAI_CHAT_DEPLOYMENT", "gpt-5.3-chat")
model_max_tokens = 128000
max_new_tokens = 200
max_prompt_len = model_max_tokens - max_new_tokens



def LLM_API(sys: str, prompt: str):
    client = AzureOpenAI(
        api_key=azure_openai_api_key,
        api_version=azure_openai_api_version,
        azure_endpoint=azure_openai_endpoint,
    )
    completion = client.chat.completions.create(
        model=model_name,
        messages=[
            {"role": "system", "content": sys},
            {"role": "user", "content": prompt}
        ]
    )
    return completion.choices[0].message.content

def call_llm(sys: str, prompt: str, return_json = True):
    retry = True
    try:
        response = LLM_API(sys, prompt)
        if return_json:
            try:
                response = response.replace('`', '').replace('json', '').replace('\n','').replace( '    ', ' ').replace('  ', ' ')
                start_index = response.find("{")
                end_index = response.rfind("}")
                data = json.loads(response[start_index:end_index + 1])
                return data

            except json.JSONDecodeError as e:
                if retry:
                    sys = sys + "Careful about comma in JSON format."
                    retry = False
                    print("JSONDecodeError", response)
                    print("JSONDecodeError, RETRY", response[start_index:end_index + 1])
                    return call_llm(sys, prompt)
                else:
                    retry = True
                    print("JSONDecodeError: ", e)
                    print("Couldn't fix the JSON", response)
                    return {}
        else:
            return response

    except Exception as e:
        print("ERROR response", e)
        sleep(2)
        if retry:
            retry = False
            return call_llm(sys, prompt)
        else:
            retry = True
            return {}

