def RelationExtraction(call_llm, text, categories, characters):
    """
    Code for node extraction
    """

    import tiktoken
    encoding = tiktoken.encoding_for_model("gpt-3.5-turbo")

    def count_string_tokens(string: str, model_name: str = "gpt-3.5-turbo") -> int:
        return len(encoding.encode(string))

    def split_text(text, max_length):
        sentences = re.split(r'(?<=[。！？])', text)
        sentence_lengths = [count_string_tokens(sentence) for sentence in sentences]
        total_tokens = sum(sentence_lengths)
        num_chunks = ceil(total_tokens / max_length)
        if num_chunks == 0:
            print(total_tokens, max_length)
        target_chunk_token_count = ceil(total_tokens / num_chunks)
        chunks = []
        current_chunk = []
        current_chunk_token_count = 0
        for sentence, length in zip(sentences, sentence_lengths):
            if current_chunk_token_count + length > target_chunk_token_count and current_chunk:
                chunks.append(''.join(current_chunk))
                current_chunk = [sentence]
                current_chunk_token_count = length
            else:
                current_chunk.append(sentence)
                current_chunk_token_count += length
        if current_chunk:
            if len(chunks) < num_chunks:
                chunks.append(''.join(current_chunk))
            else:
                chunks[-1] += ''.join(current_chunk)
        return chunks

    PROMPT = """
 Using the given relationship categories {categories}, classify the relationships between the characters listed below. 
 Note that multiple relationships categories can be applied to each character pair.

 document = {text}
 character = {characters}

 For each character, analyze their relationships based on the narrative context provided.
 Provide the relationships in the following JSON format ONLY:
 {
  "character_name": {
    "linked_character" : ["relationship_category", "relationship_category"],
    "linked_character" : ["relationship_category", "relationship_category"]
  },
  "character_name": {
    "linked_character" : ["relationship_category", "relationship_category"]
  }
 }
    """

    PROMPT_UPDATE = """
 Using the given relationship categories {categories}, classify the relationships between the characters listed below. 
 Note that multiple relationships categories can be applied to each character pair.

  Classify the character relationships, here is the known relationships:
 {relationships_graph}

 document = {text}
 character = {characters}

 For each character, analyze their relationships based on the narrative context provided.
 Provide the relationships in the following JSON format ONLY:
 {
   "character_name": {
     "linked_character" : ["relationship_category", "relationship_category"],
     "linked_character" : ["relationship_category", "relationship_category"]
   },
   "character_name": {
     "linked_character" : ["relationship_category", "relationship_category"]
   }
 }
    """

    sys = "Return Json format only"
    characters = str(characters)
    categories = str(categories)
    prompt = PROMPT.replace("{text}", text).replace("{characters}", characters).replace("{categories}", categories)
    if count_string_tokens(prompt) < model_max_tokens:
        response = call_llm(sys, prompt)

    else:
        promt_len = count_string_tokens(PROMPT.replace("{characters}", characters).replace("{categories}", categories))
        max_len = max_prompt_len - promt_len
        chunks = split_text(text, max_len)
        prompt = PROMPT.replace("{text}", chunks[0]).replace("{characters}", characters).replace("{categories}", categories)
        character_background_text = ''.join(chunks[1:])
        response = call_llm(sys, prompt)

        while True:
            promt_len = count_string_tokens(PROMPT_UPDATE.replace("{relationships_graph}", str(response)).replace("{characters}", characters).replace("{categories}", categories))
            max_len = max_prompt_len - promt_len
            if count_string_tokens(character_background_text) > max_len:
                chunks = split_text(character_background_text, max_len)
                prompt = PROMPT_UPDATE.replace("{relationships_graph}", str(response)).replace("{text}", chunks[0]).replace("{characters}", characters).replace("{categories}", categories)
                response = call_llm(sys, prompt)
                character_background_text = ''.join(chunks[1:])
            else:
                prompt = PROMPT_UPDATE.replace("{relationships_graph}", str(response)).replace("{text}", character_background_text).replace("{characters}", characters).replace("{categories}", categories)
                response = call_llm(sys, prompt)
                break

    relationships_graph = response

    return text, categories, characters, relationships_graph

