def RelationPostProcessing(call_llm, text, categories, characters, relationships_graph):
    """
    Code for node extraction
    """
    def replace_ood(ood_relation):
        PROMPT = """word = {word}
category_list = {category_list}
If there are any synonyms in category_list, return that synonym, otherwise return word.
"""
        sys = " Return the answer only."
        prompt = PROMPT.replace("{word}", ood_relation).replace("{category_list}", str(categories))
        response = call_llm(sys, prompt, return_json=False)
        if response in categories:
            return [ood_relation]
        else:
            return []

    def check_ood(relation_dict):
        """
        input: relationships graph e.g.
        output: relationships graph e.g.
        """
        result = {}
        for person, relations in relation_dict.items():
            relations_new = []
            for relation in relations:
                relation = relation.lower()
                if relation not in categories:
                    relation = replace_ood(relation)
                    relations_new += relation
                else:
                    relations_new.append(relation)
            result[person] = relations_new
        return result


    for key, value in relationships_graph.items():
        value = check_ood(value)
        relationships_graph[key] = value

    return text, categories, characters, relationships_graph

